#!/bin/bash\n# Terraform Deployment Script\n# Purpose: Initialize, validate, plan, and apply Terraform configuration\n\nset -e\n\necho \"================================================\"\necho \"  Terraform Infrastructure Deployment\"\necho \"================================================\"\n\nTF_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")\" && pwd)\"\ncd \"$TF_DIR\"\n\necho \"Working directory: $TF_DIR\"\necho \"\"\n\n# Color output\nRED='\\033[0;31m'\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nNC='\\033[0m' # No Color\n\nlog_info() {\n    echo -e \"${GREEN}[INFO]${NC} $1\"\n}\n\nlog_warn() {\n    echo -e \"${YELLOW}[WARN]${NC} $1\"\n}\n\nlog_error() {\n    echo -e \"${RED}[ERROR]${NC} $1\"\n}\n\n# Check prerequisites\nlog_info \"Checking prerequisites...\"\n\nif ! command -v terraform &> /dev/null; then\n    log_error \"terraform not found. Please install Terraform.\"\n    exit 1\nfi\n\nif ! command -v kubectl &> /dev/null; then\n    log_error \"kubectl not found. Please install kubectl.\"\n    exit 1\nfi\n\nif ! kubectl cluster-info &> /dev/null; then\n    log_error \"Cannot connect to Kubernetes cluster.\"\n    exit 1\nfi\n\nlog_info \"✓ Prerequisites met\"\necho \"\"\n\n# Terraform init\nlog_info \"Initializing Terraform...\"\nterraform init\nlog_info \"✓ Terraform initialized\"\necho \"\"\n\n# Terraform validate\nlog_info \"Validating Terraform configuration...\"\nterraform validate\nlog_info \"✓ Configuration valid\"\necho \"\"\n\n# Check for terraform.tfvars\nif [ ! -f \"terraform.tfvars\" ]; then\n    log_warn \"terraform.tfvars not found\"\n    log_info \"Creating terraform.tfvars from example...\"\n    cp terraform.tfvars.example terraform.tfvars\n    log_warn \"Please update terraform.tfvars with your values\"\nfi\n\n# Terraform plan\nlog_info \"Planning infrastructure changes...\"\nterraform plan -out=tfplan\necho \"\"\n\n# Ask for confirmation\nread -p \"Do you want to apply these changes? (yes/no): \" -r\necho \"\"\nif [[ ! $REPLY =~ ^[Yy][Ee][Ss]$ ]]; then\n    log_info \"Deployment cancelled\"\n    exit 0\nfi\n\n# Terraform apply\nlog_info \"Applying infrastructure changes...\"\nterraform apply tfplan\nlog_info \"✓ Infrastructure deployed\"\necho \"\"\n\n# Display outputs\nlog_info \"Terraform Outputs:\"\nterraform output -json | jq .\necho \"\"\n\nlog_info \"================================================\"\nlog_info \"  ✓ Terraform Deployment Complete\"\nlog_info \"================================================\"\n